#!/bin/bash
# CMDB Enterprise - Instala todos os arquivos e sobe o container
# Execute em qualquer pasta vazia:  bash setup.sh
set -e
echo "=== CMDB Enterprise Setup ==="
mkdir -p server public

echo "[1/8] docker-compose.yml"
cat > docker-compose.yml << 'EOF'
services:
  cmdb:
    build: .
    container_name: cmdb-enterprise
    restart: unless-stopped
    ports:
      - "3000:3000"
    volumes:
      - cmdb-data:/data
    environment:
      - PORT=3000
      - DATA_DIR=/data
      - SESSION_SECRET=mude-esta-chave-em-producao-2024
    healthcheck:
      test: ["CMD", "wget", "-qO-", "http://localhost:3000/api/auth/me"]
      interval: 30s
      timeout: 5s
      retries: 3
volumes:
  cmdb-data:
    driver: local
EOF

echo "[2/8] Dockerfile"
cat > Dockerfile << 'EOF'
FROM node:20-alpine
WORKDIR /app
COPY server/package*.json ./
RUN npm install --omit=dev
COPY server/server.js ./
COPY public/ ./public/
VOLUME ["/data"]
ENV DATA_DIR=/data
ENV PORT=3000
EXPOSE 3000
HEALTHCHECK --interval=30s --timeout=5s --start-period=10s \
  CMD wget -qO- http://localhost:3000/api/auth/me || exit 1
CMD ["node", "server.js"]
EOF

echo "[3/8] server/package.json"
echo "" | base64 -d > server/package.json

echo "[4/8] server/server.js"
echo "" | base64 -d > server/server.js

echo "[5/8] public/cmdb.html"
echo "" | base64 -d > public/cmdb.html

echo "[6/8] public/cmdbAPI.js"
echo "" | base64 -d > public/cmdbAPI.js

echo "[7/8] public/agent.js"
echo "" | base64 -d > public/agent.js

echo "[8/8] public/install.bat"
echo "" | base64 -d > public/install.bat

echo ""
echo "=== Arquivos criados. Subindo container... ==="
docker compose up -d --build

echo ""
echo "=== Pronto! ==="
echo "Acesse: http://$(hostname -I | awk '{print $1}'):3000"
